        .map_err(|e| (INTERNAL_ERROR, format!("{e}")))?;
    let text = serde_json::to_string_pretty(&json!({ "status": "rebuilt", "entries_indexed": count }))
        .map_err(|e| (INTERNAL_ERROR, format!("{e}")))?;
    Ok(json!({ "content": [{ "type": "text", "text": text }] }))
